package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP18LoginUsuarioNoRegistradoPlaywrightTest extends BaseTestPlaywright {    @Test    void loginConUsuarioNoRegistrado() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']")                .fill("usuariofantasma");        page.locator("input[name='password']")                .fill("cualquiera");        page.locator("button[type='submit']")                .click();        page.waitForLoadState();        assertTrue(                page.locator("input[name='username']").isVisible(),                "El campo Usuario dejó de mostrarse."        );        assertTrue(                page.locator("input[name='password']").isVisible(),                "El campo Contraseña dejó de mostrarse."        );        assertTrue(                page.url().contains("login"),                "El sistema permitió el acceso con un usuario no registrado."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP18-login-usuario-no-registrado.png"))                        .setFullPage(true)        );    }}